// 根据告警级别和执行结果构建通知消息
const data = $input.first().json;

const severityEmoji = {
  'critical': '🔴',
  'warning': '🟡',
  'info': '🟢'
}[data.severity] || '⚪';

const successEmoji = data.success ? '✅' : '❌';
const riskColor = {
  'high': 'red',
  'medium': 'orange',
  'low': 'green'
}[data.risk_level] || 'grey';

const confidencePct = Math.round((data.confidence || 0) * 100);

const feishuCard = {
  msg_type: 'interactive',
  card: {
    header: {
      title: {
        content: `${severityEmoji} KubeSentinel 自愈${data.success ? '成功' : '需人工介入'}`,
        tag: 'plain_text'
      },
      template: riskColor
    },
    elements: [
      {
        tag: 'div',
        text: {
          content: [
            `**告警名称:** ${data.alert_name}`,
            `**受影响资源:** ${data.target_resource}`,
            `**告警级别:** ${data.severity}`,
            `**AI 分析:**\n> ${data.analysis}`,
            `**执行操作:** \`${data.action_taken}\``,
            `**置信度:** ${confidencePct}%`,
            `**执行状态:** ${successEmoji} ${data.success ? '自动处理成功' : '需要人工确认'}`
          ].join('\n'),
          tag: 'lark_md'
        }
      },
      {
        tag: 'hr'
      },
      {
        tag: 'note',
        elements: [{
          tag: 'plain_text',
          content: `KubeSentinel AIOps | ${new Date().toLocaleString('zh-CN', {timeZone: 'Asia/Shanghai'})}`
        }]
      }
    ]
  }
};

// 简单文本格式（钉钉）
const dingtalkText = {
  msgtype: 'markdown',
  markdown: {
    title: `KubeSentinel: ${data.alert_name}`,
    text: [
      `## ${severityEmoji} KubeSentinel 自愈报告`,
      `**告警:** ${data.alert_name}`,
      `**目标:** ${data.target_resource}`,
      `**分析:** ${data.analysis}`,
      `**操作:** ${data.action_taken}`,
      `**结果:** ${successEmoji}`,
      '',
      `> KubeSentinel AIOps`
    ].join('\n')
  }
};

return [{
  json: {
    ...data,
    feishu_card: feishuCard,
    dingtalk_text: dingtalkText,
    notification_title: `KubeSentinel: ${data.alert_name} - ${data.success ? '已自愈' : '需人工介入'}`
  }
}];

// 汇总通知结果
const feishuResult = $('发送飞书通知').first().json;
const dingtalkResult = $('发送钉钉通知').first().json;

console.log('Feishu notification sent:', JSON.stringify(feishuResult));
console.log('DingTalk notification sent:', JSON.stringify(dingtalkResult));

return [{
  json: {
    feishu_success: feishuResult?.StatusCode === 0 || feishuResult?.ok,
    dingtalk_success: dingtalkResult?.errcode === 0,
    timestamp: new Date().toISOString()
  }
}];
